import React, { useState, useEffect, useRef } from 'react';
import adminService from '../../services/adminService';

const PRODUCTS_CACHE_KEY = 'admin_products_cache_v1';

const readCachedProducts = () => {
    try {
        const raw = localStorage.getItem(PRODUCTS_CACHE_KEY);
        if (!raw) {
            return [];
        }

        const parsed = JSON.parse(raw);
        return Array.isArray(parsed.products) ? parsed.products : [];
    } catch {
        return [];
    }
};

const readCachedCategories = () => {
    try {
        const raw = localStorage.getItem(PRODUCTS_CACHE_KEY);
        if (!raw) {
            return [];
        }

        const parsed = JSON.parse(raw);
        return Array.isArray(parsed.categories) ? parsed.categories : [];
    } catch {
        return [];
    }
};

export default function AdminProducts() {
    const [products, setProducts] = useState(() => readCachedProducts());
    const [categories, setCategories] = useState(() => readCachedCategories());
    const [error, setError] = useState('');
    const [loadIssue, setLoadIssue] = useState('');
    const [showForm, setShowForm] = useState(false);
    const [editingId, setEditingId] = useState(null);
    const [query, setQuery] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('all');
    const [currentPage, setCurrentPage] = useState(1);
    const hasSyncedRef = useRef(false);
    const [formData, setFormData] = useState({
        category_id: '',
        name: '',
        slug: '',
        brand: '',
        description: '',
        price: '',
        stock: '',
        vehicle_compatibility: '',
        image_url: '',
    });

    useEffect(() => {
        loadInitialData();
    }, []);

    useEffect(() => {
        if (!hasSyncedRef.current) {
            return;
        }

        localStorage.setItem(PRODUCTS_CACHE_KEY, JSON.stringify({
            products,
            categories,
        }));
    }, [categories, products]);

    const loadInitialData = async () => {
        await Promise.allSettled([loadProducts(), loadCategories()]);
        hasSyncedRef.current = true;
    };

    const loadProducts = async () => {
        try {
            const res = await adminService.getProducts();
            const nextProducts = res.data.data.data || res.data.data || [];
            setProducts(nextProducts);
            setLoadIssue('');
        } catch (err) {
            console.error('Failed to load products:', err);
            const status = err?.response?.status;
            if (products.length === 0) {
                if (status === 401 || status === 403) {
                    setLoadIssue('Inventory request was denied. Please log out and log in again with an admin account.');
                } else if (status === 502 || status === 503 || status === 504) {
                    setLoadIssue('Inventory service is temporarily unavailable. Please try again in a few moments.');
                } else {
                    setLoadIssue('Inventory data could not be loaded right now. Please refresh or check server connection.');
                }
            }
        }
    };

    const loadCategories = async () => {
        try {
            const res = await adminService.getCategories();
            const nextCategories = res.data.data || [];
            setCategories(nextCategories);
        } catch {
            setCategories([]);
        }
    };

    const slugify = (value) => value
        .toString()
        .toLowerCase()
        .trim()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '');

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => {
            if (name === 'name' && !prev.slug) {
                return { ...prev, [name]: value, slug: slugify(value) };
            }
            return { ...prev, [name]: value };
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        const payload = {
            category_id: formData.category_id ? Number(formData.category_id) : null,
            name: formData.name,
            slug: formData.slug || slugify(formData.name),
            brand: formData.brand,
            description: formData.description,
            price: Number(formData.price),
            stock: Number(formData.stock),
            vehicle_compatibility: formData.vehicle_compatibility || null,
            images: formData.image_url ? [formData.image_url] : [],
            is_active: true,
        };

        try {
            if (editingId) {
                await adminService.updateProduct(editingId, payload);
            } else {
                await adminService.createProduct(payload);
            }
            await loadProducts();
            resetForm();
            setShowForm(false);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to save product');
        }
    };

    const handleEdit = (product) => {
        setFormData({
            category_id: product.category_id || '',
            name: product.name || '',
            slug: product.slug || '',
            brand: product.brand || '',
            description: product.description || '',
            price: product.price ?? '',
            stock: product.stock ?? '',
            vehicle_compatibility: product.vehicle_compatibility || '',
            image_url: Array.isArray(product.images) ? (product.images[0] || '') : '',
        });
        setEditingId(product.id);
        setShowForm(true);
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this product?')) {
            try {
                await adminService.deleteProduct(id);
                await loadProducts();
            } catch (err) {
                setError('Failed to delete product');
            }
        }
    };

    const resetForm = () => {
        setFormData({
            category_id: '',
            name: '',
            slug: '',
            brand: '',
            description: '',
            price: '',
            stock: '',
            vehicle_compatibility: '',
            image_url: '',
        });
        setEditingId(null);
    };

    const getCategoryLabel = (product) => {
        const id = product.category_id;
        const match = categories.find((category) => String(category.id) === String(id));
        return match?.name || (id ? `Category ${id}` : 'Uncategorized');
    };

    const getImageUrl = (product) => {
        if (Array.isArray(product.images) && product.images.length > 0) {
            return product.images[0];
        }
        return '/images/carvex.png';
    };

    const getStockStatus = (stock) => {
        const value = Number(stock || 0);
        if (value <= 0) {
            return 'out-of-stock';
        }
        if (value <= 20) {
            return 'low-stock';
        }
        return 'in-stock';
    };

    const filteredProducts = products.filter((product) => {
        const productCategory = String(product.category_id || '');
        const categoryMatch = selectedCategory === 'all' || productCategory === selectedCategory;

        const q = query.trim().toLowerCase();
        const haystack = [
            product.name,
            product.slug,
            product.brand,
        ]
            .filter(Boolean)
            .join(' ')
            .toLowerCase();
        const textMatch = q === '' || haystack.includes(q);

        return categoryMatch && textMatch;
    });

    const itemsPerPage = 5;
    const totalPages = Math.max(1, Math.ceil(filteredProducts.length / itemsPerPage));
    const safeCurrentPage = Math.min(currentPage, totalPages);
    const startIndex = (safeCurrentPage - 1) * itemsPerPage;
    const paginatedProducts = filteredProducts.slice(startIndex, startIndex + itemsPerPage);
    const showingFrom = filteredProducts.length === 0 ? 0 : startIndex + 1;
    const showingTo = Math.min(startIndex + paginatedProducts.length, filteredProducts.length);

    useEffect(() => {
        setCurrentPage(1);
    }, [query, selectedCategory]);

    useEffect(() => {
        if (currentPage > totalPages) {
            setCurrentPage(totalPages);
        }
    }, [currentPage, totalPages]);

    const totalValue = filteredProducts.reduce((sum, product) => sum + Number(product.price || 0), 0);
    const lowStockItems = filteredProducts.filter((product) => {
        const stock = Number(product.stock || 0);
        return stock > 0 && stock <= 20;
    }).length;

    return (
        <div className="admin-page-content admin-products">
            <div className="inventory-header-row">
                <div>
                    <h2>Inventory Management</h2>
                    <p>Manage your car parts inventory</p>
                </div>

                <button
                    className="btn btn-primary add-part-btn"
                    onClick={() => {
                        resetForm();
                        setShowForm(!showForm);
                    }}
                >
                    + Add New Part
                </button>
            </div>

            <div className="inventory-card">
                <div className="inventory-toolbar">
                    <div className="inventory-search">
                        <span className="inventory-search-icon" aria-hidden="true">
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <circle cx="11" cy="11" r="7" />
                                <path d="m20 20-3.5-3.5" />
                            </svg>
                        </span>
                        <input
                            type="text"
                            placeholder="Search by name or SKU..."
                            value={query}
                            onChange={(e) => setQuery(e.target.value)}
                        />
                    </div>
                    <div className="inventory-filter">
                        <span className="inventory-filter-icon" aria-hidden="true">
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M3 5h18l-7 8v6l-4-2v-4L3 5Z" />
                            </svg>
                        </span>
                        <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
                            <option value="all">All Categories</option>
                            {categories.map((category) => (
                                <option key={category.id} value={String(category.id)}>{category.name}</option>
                            ))}
                        </select>
                    </div>
                </div>

                <div className="products-table">
                    <table>
                        <thead>
                            <tr>
                                <th>Image</th>
                                <th>Part Name</th>
                                <th>SKU</th>
                                <th>Category</th>
                                <th>Price</th>
                                <th>Stock</th>
                                <th>Status</th>
                                <th>Supplier</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {paginatedProducts.length > 0 ? paginatedProducts.map((product) => {
                                const status = getStockStatus(product.stock);

                                return (
                                    <tr key={product.id}>
                                        <td>
                                            <img src={getImageUrl(product)} alt={product.name} className="product-thumb" />
                                        </td>
                                        <td className="part-name">{product.name}</td>
                                        <td>{product.slug || `SKU-${product.id}`}</td>
                                        <td>{getCategoryLabel(product)}</td>
                                        <td>₱{parseFloat(product.price || 0).toFixed(2)}</td>
                                        <td>{product.stock}</td>
                                        <td>
                                            <span className={`stock-pill ${status}`}>{status.replace('-', ' ')}</span>
                                        </td>
                                        <td>{product.brand || '-'}</td>
                                        <td className="actions">
                                            <button className="icon-btn" onClick={() => handleEdit(product)} aria-label="Edit product">
                                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                    <path d="M12 20h9" />
                                                    <path d="m16.5 3.5 4 4L7 21H3v-4L16.5 3.5Z" />
                                                </svg>
                                            </button>
                                            <button className="icon-btn icon-btn--danger" onClick={() => handleDelete(product.id)} aria-label="Delete product">
                                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                    <path d="M3 6h18" />
                                                    <path d="M8 6V4h8v2" />
                                                    <path d="m19 6-1 14H6L5 6" />
                                                </svg>
                                            </button>
                                        </td>
                                    </tr>
                                );
                            }) : (
                                <tr>
                                    <td colSpan="9" className="orders-empty-state">
                                        {loadIssue || 'No products found for the current filters.'}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="inventory-status-bar">
                <span>Showing {showingFrom}-{showingTo} of {filteredProducts.length} parts</span>
                <div className="pagination-controls" aria-hidden="true">
                    <button type="button" onClick={() => setCurrentPage((prev) => Math.max(prev - 1, 1))} disabled={safeCurrentPage === 1}>Previous</button>
                    <button type="button" onClick={() => setCurrentPage((prev) => Math.min(prev + 1, totalPages))} disabled={safeCurrentPage >= totalPages}>Next</button>
                </div>
            </div>

            <section className="inventory-summary-grid">
                <article className="inventory-summary-card">
                    <p>Total Parts</p>
                    <strong>{filteredProducts.length}</strong>
                </article>
                <article className="inventory-summary-card inventory-summary-card--value">
                    <p>Total Value</p>
                    <strong>₱{totalValue.toFixed(2)}</strong>
                </article>
                <article className="inventory-summary-card inventory-summary-card--alert">
                    <p>Low Stock Items</p>
                    <strong>{lowStockItems}</strong>
                </article>
            </section>

            {showForm && (
                <div className="modal-backdrop" onClick={() => setShowForm(false)}>
                    <div className="form-card" onClick={(e) => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>{editingId ? 'Edit Part' : 'Add New Part'}</h2>
                            <button
                                type="button"
                                className="modal-close"
                                onClick={() => setShowForm(false)}
                            >
                                Close
                            </button>
                        </div>
                        <form onSubmit={handleSubmit}>
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Name</label>
                                    <input
                                        type="text"
                                        name="name"
                                        value={formData.name}
                                        onChange={handleChange}
                                        required
                                    />
                                </div>
                                <div className="form-group">
                                    <label>Brand</label>
                                    <input
                                        type="text"
                                        name="brand"
                                        value={formData.brand}
                                        onChange={handleChange}
                                        required
                                    />
                                </div>
                                <div className="form-group">
                                    <label>Category</label>
                                    <select name="category_id" value={formData.category_id} onChange={handleChange}>
                                        <option value="">Uncategorized</option>
                                        {categories.map((category) => (
                                            <option key={category.id} value={category.id}>{category.name}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label>Price</label>
                                    <input
                                        type="number"
                                        name="price"
                                        value={formData.price}
                                        onChange={handleChange}
                                        step="0.01"
                                        required
                                    />
                                </div>
                                <div className="form-group">
                                    <label>Stock</label>
                                    <input
                                        type="number"
                                        name="stock"
                                        value={formData.stock}
                                        onChange={handleChange}
                                        required
                                    />
                                </div>
                                <div className="form-group">
                                    <label>SKU (Slug)</label>
                                    <input
                                        type="text"
                                        name="slug"
                                        value={formData.slug}
                                        onChange={handleChange}
                                        placeholder="auto-generated-if-empty"
                                    />
                                </div>
                            </div>

                            <div className="form-group">
                                <label>Description</label>
                                <textarea
                                    name="description"
                                    value={formData.description}
                                    onChange={handleChange}
                                    rows="4"
                                    required
                                ></textarea>
                            </div>

                            <div className="form-group">
                                <label>Image URL</label>
                                <input
                                    type="text"
                                    name="image_url"
                                    value={formData.image_url}
                                    onChange={handleChange}
                                    placeholder="https://..."
                                />
                            </div>

                            <div className="form-actions">
                                <button type="button" className="btn btn-outline" onClick={() => setShowForm(false)}>
                                    Cancel
                                </button>
                                <button type="submit" className="btn btn-primary">
                                    {editingId ? 'Update Part' : 'Save Part'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
